const now = new Date();
const today = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const yesterday = new Date(now - 86400000).toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const dayOfWeek = now.toLocaleDateString('en-US', { weekday: 'long', timeZone: 'America/Chicago' });
return [{ json: { today, yesterday, dayOfWeek } }];

const { today, yesterday, dayOfWeek } = $('Set Dates').first().json;

// MTL is passed through S3: Read MTL -> S3: Read Yesterday Log chain
// Both nodes use continueOnFail so they pass their json/binary forward
let mtlContent = '';
try {
  const bin = $('S3: Read MTL').first().binary?.data;
  if (bin) mtlContent = Buffer.from(bin.data, 'base64').toString('utf-8');
} catch(e) {}

const overdue = [];
const dueToday = [];
const re = /^- \\[ \\] (.+?)\\[area:: (\\w+)\\].*?\\[priority:: ([ABC])\\].*?\\[due:: (\\d{4}-\\d{2}-\\d{2})\\]/gm;
let m;
while ((m = re.exec(mtlContent)) !== null) {
  const item = { task: m[1].trim(), area: m[2], priority: m[3], due: m[4] };
  if (m[4] < today) {
    item.daysOverdue = Math.floor((new Date(today) - new Date(m[4])) / 86400000);
    overdue.push(item);
  } else if (m[4] === today) {
    dueToday.push(item);
  }
}
overdue.sort((a,b) => a.priority < b.priority ? -1 : a.priority > b.priority ? 1 : b.daysOverdue - a.daysOverdue);
dueToday.sort((a,b) => a.priority < b.priority ? -1 : 1);

let capturedTasks = 0, capturedArticles = 0;
try {
  const bin = $('S3: Read Yesterday Log').first().binary?.data;
  if (bin) {
    const log = JSON.parse(Buffer.from(bin.data, 'base64').toString('utf-8'));
    capturedTasks = log.tasks_extracted || log.task_count || 0;
    capturedArticles = log.articles_queued || log.article_count || 0;
  }
} catch(e) {}

const areaEmoji = { faith:'🙏', family:'👨‍👩‍👧', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🎯' };

function taskRow(t) {
  const badge = t.priority === 'A' ? '<span style="color:#c0392b;font-weight:bold">[A]</span>' : t.priority === 'B' ? '<span style="color:#e67e22">[B]</span>' : '<span style="color:#7f8c8d">[C]</span>';
  const overdueTxt = t.daysOverdue ? ` <em style="color:#e74c3c">(${t.daysOverdue}d overdue)</em>` : '';
  return `<li>${badge} ${t.task} <small>due: ${t.due}</small>${overdueTxt}</li>`;
}

function areaSection(items) {
  const byArea = {};
  for (const t of items) { if (!byArea[t.area]) byArea[t.area] = []; byArea[t.area].push(t); }
  return Object.entries(byArea).map(([area, tasks]) =>
    `<h4>${areaEmoji[area] || '📌'} ${area.charAt(0).toUpperCase()+area.slice(1)}</h4><ul>${tasks.map(taskRow).join('')}</ul>`
  ).join('');
}

let html = `<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;color:#2c3e50"><h1 style="border-bottom:3px solid #3498db;padding-bottom:8px">🌅 Morning Briefing — ${dayOfWeek}, ${today}</h1>`;

html += overdue.length > 0
  ? `<div style="background:#fdf2f2;border-left:4px solid #e74c3c;padding:12px;margin:16px 0"><h2 style="color:#e74c3c;margin-top:0">🔥 Overdue — ${overdue.length} task${overdue.length>1?'s':''}</h2>${areaSection(overdue)}</div>`
  : `<div style="background:#eafaf1;border-left:4px solid #27ae60;padding:12px;margin:16px 0"><p>✅ No overdue tasks — you're caught up!</p></div>`;

html += dueToday.length > 0
  ? `<div style="background:#fef9e7;border-left:4px solid #f39c12;padding:12px;margin:16px 0"><h2 style="color:#f39c12;margin-top:0">📅 Due Today — ${dueToday.length} task${dueToday.length>1?'s':''}</h2>${areaSection(dueToday)}</div>`
  : `<div style="padding:12px;margin:16px 0"><h2>📅 Due Today</h2><p style="color:#7f8c8d"><em>Nothing scheduled — great day to get ahead.</em></p></div>`;

html += capturedTasks > 0 || capturedArticles > 0
  ? `<div style="background:#eaf3fb;border-left:4px solid #3498db;padding:12px;margin:16px 0"><h2 style="color:#3498db;margin-top:0">📥 Yesterday's Captures</h2><ul><li><strong>${capturedTasks}</strong> tasks extracted</li><li><strong>${capturedArticles}</strong> articles queued</li></ul></div>`
  : `<div style="padding:12px;margin:16px 0"><h2>📥 Yesterday's Captures</h2><p style="color:#7f8c8d"><em>No brain dump processed yesterday.</em></p></div>`;

html += `<div style="background:#f4f6f7;border-left:4px solid #95a5a6;padding:12px;margin:16px 0"><h2 style="margin-top:0">🎯 Q2 2026 Rocks</h2><ul><li>🙏 Faith: Social media Bible study (4 sessions)</li><li>👨‍👩‍👧 Family: Marriage Alignment + bi-weekly check-in</li><li>🚀 Business: MVP — website, offer, 3 outreach convos</li><li>🏥 Work: Deliver Union project</li><li>💪 Health: Hip decision + 3x/week gym x8 weeks</li></ul></div>`;
html += `<p style="color:#95a5a6;font-size:12px;text-align:center">Generated ${new Date().toISOString()}</p></div>`;

return [{ json: { html, today, dayOfWeek, overdueCount: overdue.length, todayCount: dueToday.length, capturedTasks, capturedArticles, bodyLength: html.length } }];

const j = $input.first().json;
const log = JSON.stringify({ workflow: 'morning-briefing', run_date: j.today, finished_at: new Date().toISOString(), status: 'success', overdue_count: j.overdueCount, today_count: j.todayCount, body_length: j.bodyLength }, null, 2);
return [{ json: { logKey: `99_System/logs/morning-briefing-${j.today}.json`, logContent: log } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
